+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track = {min: number; fr: number; auto: boolean};
+type Placement = {start: number; end: number};
+
+const trackPattern = /minmax\\([^)]*\\)|[^\\s]+/g;
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	return (template.match(trackPattern) ?? []).map(token => {
+		if (token.startsWith('minmax(')) {
+			const [minimum, maximum] = token.slice(7, -1).split(',').map(part => part.trim());
+			return {min: Number(minimum), fr: maximum.endsWith('fr') ? Number.parseFloat(maximum) || 1 : 0, auto: false};
+		}
+
+		if (token === 'auto') return {min: 0, fr: 0, auto: true};
+		if (token.endsWith('fr')) return {min: 0, fr: Number.parseFloat(token) || 1, auto: false};
+		return {min: Number(token), fr: 0, auto: false};
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') return {start: value - 1, end: value};
+	if (!value) return undefined;
+	const [start, end] = value.split('/').map(part => Number(part.trim()));
+	if (!Number.isFinite(start)) return undefined;
+	return {start: start - 1, end: Number.isFinite(end) ? end - 1 : start};
+};
+
+const distributeTracks = (tracks: Track[], available: number, gap: number, autoSizes: number[]): number[] => {
+	const sizes = tracks.map((track, index) => track.auto ? autoSizes[index] ?? 0 : track.min);
+	const remaining = Math.max(0, available - sizes.reduce((sum, size) => sum + size, 0) - Math.max(0, tracks.length - 1) * gap);
+	const totalFr = tracks.reduce((sum, track) => sum + track.fr, 0);
+	return sizes.map((size, index) => totalFr > 0 ? size + remaining * tracks[index].fr / totalFr : size);
+};
+
+const sumRange = (sizes: number[], start: number, end: number, gap: number) =>
+	sizes.slice(start, end).reduce((sum, size) => sum + size, 0) + Math.max(0, end - start - 1) * gap;
+
+const offsetFor = (sizes: number[], index: number, gap: number) =>
+	sizes.slice(0, index).reduce((sum, size) => sum + size, 0) + index * gap;
+
+const elementChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && child.yogaNode !== undefined);
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode!;
+	const layout = yogaNode.getComputedLayout();
+	const leftPadding = yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + yogaNode.getComputedBorder(Yoga.EDGE_LEFT);
+	const rightPadding = yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) + yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const topPadding = yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_TOP);
+	const bottomPadding = yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) return;
+	const children = elementChildren(node).filter(child => child.style.display !== 'none');
+	const placements = new Map<DOMElement, {column: Placement; row: Placement}>();
+	let nextColumn = 0;
+	let nextRow = 0;
+	let requiredRows = 0;
+	for (const child of children) {
+		let column = parsePlacement(child.style.gridColumn);
+		let row = parsePlacement(child.style.gridRow);
+		if (!column) {
+			column = {start: nextColumn, end: nextColumn + 1};
+		}
+		if (!row) row = {start: nextRow, end: nextRow + 1};
+		placements.set(child, {column, row});
+		requiredRows = Math.max(requiredRows, row.end);
+		nextColumn = column.end;
+		nextRow = row.start;
+		if (nextColumn >= columns.length) { nextColumn = 0; nextRow++; }
+	}
+
+	const rowTemplate = parseTracks(node.style.gridTemplateRows);
+	const rows = [...rowTemplate];
+	while (rows.length < requiredRows) rows.push({min: 0, fr: 0, auto: true});
+	const columnAutoSizes = columns.map(() => 0);
+	const rowAutoSizes = rows.map(() => 0);
+	for (const child of children) {
+		const placement = placements.get(child)!;
+		const childLayout = child.yogaNode!.getComputedLayout();
+		if (placement.column.end - placement.column.start === 1 && columns[placement.column.start]?.auto) columnAutoSizes[placement.column.start] = Math.max(columnAutoSizes[placement.column.start], childLayout.width);
+		if (placement.row.end - placement.row.start === 1 && rows[placement.row.start]?.auto) rowAutoSizes[placement.row.start] = Math.max(rowAutoSizes[placement.row.start], childLayout.height);
+	}
+	const width = Math.max(0, layout.width - leftPadding - rightPadding);
+	const columnSizes = distributeTracks(columns, width, columnGap, columnAutoSizes);
+	const explicitHeight = typeof node.style.height === 'number';
+	const availableHeight = Math.max(0, layout.height - topPadding - bottomPadding);
+	const rowSizes = distributeTracks(rows, explicitHeight ? availableHeight : 0, rowGap, rowAutoSizes);
+	const contentHeight = rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap;
+	if (!explicitHeight) yogaNode.setHeight(contentHeight + topPadding + bottomPadding);
+
+	for (const child of children) {
+		const {column, row} = placements.get(child)!;
+		const childYoga = child.yogaNode!;
+		childYoga.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.internal_gridItem = true;
+		childYoga.setPosition(Yoga.EDGE_LEFT, offsetFor(columnSizes, column.start, columnGap));
+		childYoga.setPosition(Yoga.EDGE_TOP, offsetFor(rowSizes, row.start, rowGap));
+		childYoga.setWidth(sumRange(columnSizes, column.start, column.end, columnGap));
+		childYoga.setHeight(sumRange(rowSizes, row.start, row.end, rowGap));
+	}
+};
+
+export const applyGridLayout = (node: DOMNode): void => {
+	if (node.nodeName === '#text') return;
+	for (const child of elementChildren(node)) applyGridLayout(child);
+	if (node.style.display === 'grid') layoutGrid(node);
+	else {
+		for (const child of elementChildren(node)) {
+			if (child.internal_gridItem) {
+				child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+				child.internal_gridItem = false;
+			}
+		}
+	}
+};
